function normalizarTipoClassificacao(tipo) {
  return String(tipo || '').toUpperCase().trim();
}

function prefixoTipoClassificacao(tipo) {
  switch (normalizarTipoClassificacao(tipo)) {
    case 'GENERICOS': return 'Opcao Generica (Mais economica)';
    case 'SIMILARES': return 'Opcao Similar';
    case 'REFERENCIA':
    case 'RX':
      return 'Opcao de Referencia';
    default: return 'Opcao Disponivel';
  }
}

function montarDescricaoLinhaUnica(item) {
  let descCompleta = item.desc;
  const prefixo = prefixoTipoClassificacao(item.tipoClassificacao);
  descCompleta = prefixo + ' - ' + descCompleta;
  if (item.badge) descCompleta = item.badge + ' - ' + descCompleta;
  descCompleta += ' | ' + item.price;
  if (item.infoOferta) descCompleta += item.infoOferta;
  return descCompleta;
}

function processarProduto(produto) {
  if (!produto || typeof produto !== 'object') return null;

  const nomeCompleto = produto.nome || produto.descricao || produto.descricao_provider || produto.descricao_alpha7 || '';
  if (!nomeCompleto) return null;

  const estoqueDisponivel = Number(produto.estoque_disponivel ?? produto.estoque ?? 0) || 0;

  // Se quiser mostrar mesmo sem estoque, remova este bloco.
  if (estoqueDisponivel <= 0) return null;

  const codigo = String(produto.codigo_barras || produto.codigo || produto.id || '-');
  const precoFinal = Number(produto.precos?.preco_final ?? produto.precos?.preco_venda ?? 0) || 0;
  const precoCheio = Number(
    produto.precos?.preco_sem_desconto ??
    produto.precos?.preco_venda ??
    produto.precos?.preco_final ??
    0
  ) || null;
  const desconto = Number(produto.precos?.desconto_percentual ?? 0) || 0;

  if (precoFinal <= 0) return null;

  let preco = '';
  let temOferta = false;

  if (precoCheio && precoFinal < precoCheio) {
    preco = 'De R$ ' + precoCheio.toFixed(2) + ' por R$ ' + precoFinal.toFixed(2) + ' (' + desconto.toFixed(0) + '% OFF)';
    temOferta = true;
  } else {
    preco = 'R$ ' + precoFinal.toFixed(2);
  }

  let infoOferta = '';
  if (produto.precos?.tem_oferta_ativa && produto.precos?.nome_campanha) {
    infoOferta = ' | Campanha: ' + produto.precos.nome_campanha;
  }

  return {
    desc: nomeCompleto,
    price: preco,
    id: String(codigo),
    faixa: null,
    temOferta,
    estoque: estoqueDisponivel,
    precoFinal,
    precoCheio,
    infoOferta,
    tipoClassificacao: normalizarTipoClassificacao(
      produto.grupo || produto.classificacao_nome_origem || produto.tipo_classificacao || ''
    ),
    badge: null
  };
}

const todosProcessados = [];
