} else {
  productList = [...todosProcessados].slice(0, 5);
  productList.forEach((p) => { p.desc = montarDescricaoLinhaUnica(p); });
}

const top3ParaChecagem = productList.slice(0, 3);
const top3TemGenerico = top3ParaChecagem.some((p) => p.tipoClassificacao === 'GENERICOS');

let opcoesGenericas = [];
if (!top3TemGenerico) {
  const idsVistos = new Set();
  opcoesGenericas = [...todosProcessados]
